mapper.update:
UPDATE post_ai_result
   SET status = 'FAILED', error_message = #{errorMessage}, completed_at = NOW()
 WHERE post_id = #{postId} AND task_type = #{taskType}

mapper.select:
SELECT cp.id AS post_id, cp.title, cp.category AS post_category, cp.status AS post_status, cp.is_anonymous AS anonymous, cp.user_id AS author_id, u.name AS author_name, ar.result_json, ar.model, ar.attempt_count, ar.status AS ai_status, cp.created_at, ar.completed_at FROM post_ai_result ar JOIN community_post cp ON ar.post_id = cp.id LEFT JOIN users u ON cp.user_id = u.id WHERE ar.task_type = 'MODERATION'
AND cp.status = #{status}
AND JSON_EXTRACT(ar.result_json, '$.toxic') = #{toxic}
ORDER BY ar.completed_at DESC, cp.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
  FROM post_ai_result ar
  JOIN community_post cp ON ar.post_id = cp.id
 WHERE ar.task_type = 'MODERATION'

   AND cp.status = #{status}


   AND JSON_EXTRACT(ar.result_json, '$.toxic') = #{toxic}
